      timestamp: "2023-12-27 8:50:11",
    },{
      id: "1012",
      title: "L",
      content: "Hi Hello L",
      timestamp: "2023-12-27 8:50:11",
    },
  ];
  
  return (
    <div className="dashboard flex w-[100vw] h-[100vh]">
      <div className="w-[25%] bg-[#4B4453]">
        <DashboardMenu updatePageContent={updatePageContent} data={data}/>
      </div>
      <div className="w-[75%] bg-[#B0A8B9]">
        <DashboardContent pagecontent={pagecontent}/>
      </div>
    </div>
  );
};
